# solution.py
"""Team_Collaboration_Manager.

A self-contained, thread-safe, in-memory team collaboration platform.

The module exposes a single facade -- :class:`TeamCollaborationManager` -- that
manages users, projects, tasks, messaging, a performance dashboard, and report
generation/export.  It is intentionally dependency-free (standard library only)
so that it is easy to embed, test, and reason about.

Design notes
------------
* **Global identifiers.**  Every persisted entity (user, project, task, message,
  rating) draws from a single monotonically increasing counter, so identifiers
  are unique across every entity type and start at ``1``.
* **Thread safety.**  A single re-entrant lock guards every mutating and reading
  operation.  All internal data stores share that exact same lock instance, which
  keeps cross-entity operations (cascades, index maintenance) atomic.
* **Getter isolation.**  Public read methods always return *clones* of the stored
  objects (and fresh lists/dicts), so callers can never mutate internal state by
  holding onto a returned reference.
"""

import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a registered user may hold."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for a generated report."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Categories of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by this module."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor attempts an operation they may not perform."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing related state."""


# ---------------------------------------------------------------------------
# Domain models
# ---------------------------------------------------------------------------
class Attachment(object):
    """A binary file attached to a message (only metadata is retained)."""

    __slots__ = ("filename", "size", "uploaded_by", "uploaded_at")

    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def clone(self):
        return Attachment(self.filename, self.size, self.uploaded_by, self.uploaded_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Attachment(filename={0!r}, size={1})".format(self.filename, self.size)


class User(object):
    """An account on the platform."""

    __slots__ = ("id", "username", "email", "role", "created_at")

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def clone(self):
        return User(self.id, self.username, self.email, self.role, self.created_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "User(id={0}, username={1!r})".format(self.id, self.username)


class Project(object):
    """A unit of work with an owner and a date range."""

    __slots__ = (
        "id",
        "name",
        "description",
        "start_date",
        "end_date",
        "owner_id",
        "created_at",
    )

    def __init__(self, id, name, description, start_date, end_date, owner_id, created_at):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at

    def clone(self):
        return Project(
            self.id,
            self.name,
            self.description,
            self.start_date,
            self.end_date,
            self.owner_id,
            self.created_at,
        )

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Project(id={0}, name={1!r})".format(self.id, self.name)


class Task(object):
    """A single actionable item belonging to a project."""

    __slots__ = (
        "id",
        "project_id",
        "title",
        "status",
        "assignee_id",
        "deadline",
        "started_at",
        "completed_at",
        "created_at",
    )

    def __init__(
        self,
        id,
        project_id,
        title,
        status,
        assignee_id,
        deadline,
        started_at,
        completed_at,
        created_at,
    ):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.started_at = started_at
        self.completed_at = completed_at
        self.created_at = created_at

    def clone(self):
        return Task(
            self.id,
            self.project_id,
            self.title,
            self.status,
            self.assignee_id,
            self.deadline,
            self.started_at,
            self.completed_at,
            self.created_at,
        )

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Task(id={0}, title={1!r}, status={2})".format(
            self.id, self.title, self.status
        )


class Message(object):
    """A message posted to either a project or a task thread."""

    __slots__ = (
        "id",
        "author_id",
        "body",
        "project_id",
        "task_id",
        "parent_id",
        "attachments",
        "created_at",
        "edited_at",
    )

    def __init__(
        self,
        id,
        author_id,
        body,
        project_id,
        task_id,
        parent_id,
        attachments,
        created_at,
        edited_at,
    ):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments
        self.created_at = created_at
        self.edited_at = edited_at

    def clone(self):
        return Message(
            self.id,
            self.author_id,
            self.body,
            self.project_id,
            self.task_id,
            self.parent_id,
            [a.clone() for a in self.attachments],
            self.created_at,
            self.edited_at,
        )

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Message(id={0}, author_id={1})".format(self.id, self.author_id)


class Rating(object):
    """A peer rating of a user's performance."""

    __slots__ = (
        "id",
        "rater_id",
        "ratee_id",
        "score",
        "feedback",
        "task_id",
        "created_at",
    )

    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id, created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def clone(self):
        return Rating(
            self.id,
            self.rater_id,
            self.ratee_id,
            self.score,
            self.feedback,
            self.task_id,
            self.created_at,
        )

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Rating(id={0}, score={1})".format(self.id, self.score)


# ---------------------------------------------------------------------------
# Internal data stores
# ---------------------------------------------------------------------------
class _BaseStore(object):
    """Common base that shares a single lock instance with its siblings."""

    def __init__(self, lock):
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super(_UserStore, self).__init__(lock)
        self.items = {}
        self.by_username = {}
        self.by_email = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super(_ProjectStore, self).__init__(lock)
        self.items = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super(_TaskStore, self).__init__(lock)
        self.items = {}
        self.by_project = {}
        self.by_assignee = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super(_MessageStore, self).__init__(lock)
        self.items = {}
        self.by_project = {}
        self.by_task = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super(_PerformanceStore, self).__init__(lock)
        self.ratings_by_ratee = {}


class _ReportStore(_BaseStore):
    """Reports are computed on demand; this store only carries the shared lock."""


# ---------------------------------------------------------------------------
# Helper functions
# ---------------------------------------------------------------------------
def _csv_value(value):
    if value is None:
        return ""
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, Enum):
        return value.value
    if isinstance(value, datetime):
        return value.isoformat()
    return str(value)


def _pdf_escape(text):
    out = []
    for ch in text:
        if ch in ("\\", "(", ")"):
            out.append("\\" + ch)
        elif ch in ("\n", "\r", "\t"):
            out.append(" ")
        elif 32 <= ord(ch) < 127:
            out.append(ch)
        else:
            out.append(" ")
    return "".join(out)


# ---------------------------------------------------------------------------
# Facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager(object):
    """The single entry point for the collaboration platform."""

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        # Every store shares the manager's lock instance.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal helpers (assume the lock is already held) ------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    def _require_user(self, user_id):
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _index_assignee(self, assignee_id, task_id):
        if assignee_id is None:
            return
        self.tasks.by_assignee.setdefault(assignee_id, set()).add(task_id)

    def _deindex_assignee(self, assignee_id, task_id):
        if assignee_id is None:
            return
        bucket = self.tasks.by_assignee.get(assignee_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                del self.tasks.by_assignee[assignee_id]

    def _tasks_for_assignee(self, assignee_id):
        ids = self.tasks.by_assignee.get(assignee_id, set())
        return [self.tasks.items[tid] for tid in ids if tid in self.tasks.items]

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    @staticmethod
    def _validate_username(username):
        if not isinstance(username, str):
            raise ValidationError("username must be a string")
        cleaned = username.strip()
        if not cleaned:
            raise ValidationError("username must not be empty")
        return cleaned

    # ------------------------------------------------------------------ users
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            clean_username = self._validate_username(username)
            clean_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if clean_username in self.users.by_username:
                raise DuplicateError("username already registered")
            if clean_email in self.users.by_email:
                raise DuplicateError("email already registered")

            user_id = self._next_id()
            user = User(user_id, clean_username, clean_email, role, self._now())
            self.users.items[user_id] = user
            self.users.by_username[clean_username] = user_id
            self.users.by_email[clean_email] = user_id
            return user.clone()

    def get_user(self, user_id):
        with self._lock:
            return self._require_user(user_id).clone()

    def list_users(self):
        with self._lock:
            return [
                self.users.items[uid].clone()
                for uid in sorted(self.users.items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            new_username = user.username
            if username is not None:
                new_username = self._validate_username(username)
                existing = self.users.by_username.get(new_username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already registered")

            new_email = user.email
            if email is not None:
                new_email = self._validate_email(email)
                existing = self.users.by_email.get(new_email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already registered")

            new_role = user.role
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                del self.users.by_username[user.username]
                self.users.by_username[new_username] = user_id
                user.username = new_username
            if new_email != user.email:
                del self.users.by_email[user.email]
                self.users.by_email[new_email] = user_id
                user.email = new_email
            user.role = new_role
            return user.clone()

    def delete_user(self, user_id):
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for task in self._tasks_for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            # Detach the (only completed) tasks from the assignee index.
            self.tasks.by_assignee.pop(user_id, None)

            del self.users.items[user_id]
            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)

    # --------------------------------------------------------------- projects
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must not be empty")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            self._require_user(owner_id)

            project_id = self._next_id()
            project = Project(
                project_id,
                name,
                description,
                start_date,
                end_date,
                owner_id,
                self._now(),
            )
            self.projects.items[project_id] = project
            self.tasks.by_project.setdefault(project_id, [])
            self.messages.by_project.setdefault(project_id, [])
            return project.clone()

    def get_project(self, project_id):
        with self._lock:
            return self._require_project(project_id).clone()

    def list_projects(self):
        with self._lock:
            return [
                self.projects.items[pid].clone()
                for pid in sorted(self.projects.items)
            ]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None, description=None
    ):
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not None:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must not be empty")
                new_name = name

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return project.clone()

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks.by_project.get(project_id, []))
            for task_id in task_ids:
                task = self.tasks.items.pop(task_id, None)
                if task is not None:
                    self._deindex_assignee(task.assignee_id, task_id)
                # Remove any messages threaded under this task.
                for message_id in self.messages.by_task.pop(task_id, []):
                    self.messages.items.pop(message_id, None)
            self.tasks.by_project.pop(project_id, None)

            for message_id in self.messages.by_project.pop(project_id, []):
                self.messages.items.pop(message_id, None)

            del self.projects.items[project_id]

    # ------------------------------------------------------------------ tasks
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must not be empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task_id = self._next_id()
            task = Task(
                task_id,
                project_id,
                title,
                TaskStatus.NOT_STARTED,
                assignee_id,
                deadline,
                None,
                None,
                self._now(),
            )
            self.tasks.items[task_id] = task
            self.tasks.by_project.setdefault(project_id, []).append(task_id)
            self._index_assignee(assignee_id, task_id)
            return task.clone()

    def get_task(self, task_id):
        with self._lock:
            return self._require_task(task_id).clone()

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks.by_project.get(project_id, [])
            return [self.tasks.items[tid].clone() for tid in sorted(ids)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            tasks = self._tasks_for_assignee(assignee_id)
            return [task.clone() for task in sorted(tasks, key=lambda t: t.id)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            if task.assignee_id != assignee_id:
                self._deindex_assignee(task.assignee_id, task_id)
                task.assignee_id = assignee_id
                self._index_assignee(assignee_id, task_id)
            return task.clone()

    def reassign_task(self, task_id, new_assignee_id):
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            if task.assignee_id is not None:
                self._deindex_assignee(task.assignee_id, task_id)
                task.assignee_id = None
            return task.clone()

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return task.clone()

    # --------------------------------------------------------------- messages
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ):
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            attachment_specs = list(attachments) if attachments else []
            text = body if isinstance(body, str) else ""
            if not text.strip() and not attachment_specs:
                raise ValidationError("message body must not be empty")

            self._require_user(author_id)
            if project_id is not None:
                self._require_project(project_id)
            else:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            built = []
            for spec in attachment_specs:
                filename, data = spec
                if not isinstance(filename, str) or not filename:
                    raise ValidationError("attachment filename must not be empty")
                built.append(Attachment(filename, len(data), author_id, now))

            message_id = self._next_id()
            message = Message(
                message_id,
                author_id,
                body,
                project_id,
                task_id,
                parent_id,
                built,
                now,
                None,
            )
            self.messages.items[message_id] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, []).append(message_id)
            else:
                self.messages.by_task.setdefault(task_id, []).append(message_id)
            return message.clone()

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must not be empty")
            message.body = new_body
            message.edited_at = self._now()
            return message.clone()

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach files")
            if not isinstance(filename, str) or not filename:
                raise ValidationError("attachment filename must not be empty")
            message.attachments.append(
                Attachment(filename, len(data), uploader_id, self._now())
            )
            return message.clone()

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.messages.by_project.get(project_id, [])
            return [self.messages.items[mid].clone() for mid in sorted(ids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = self.messages.by_task.get(task_id, [])
            return [self.messages.items[mid].clone() for mid in sorted(ids)]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            del self.messages.items[message_id]
            if message.project_id is not None:
                bucket = self.messages.by_project.get(message.project_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = self.messages.by_task.get(message.task_id)
                if bucket and message_id in bucket:
                    bucket.remove(message_id)

    # ----------------------------------------------------------- performance
    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / float(len(tasks))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._tasks_for_assignee(user_id))
            if not durations:
                return None
            return sum(durations) / float(len(durations))

    @staticmethod
    def _completion_durations(tasks):
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if rater_id == ratee_id:
                raise ConflictError("a user may not rate themselves")
            if not isinstance(score, (int, float)) or isinstance(score, bool):
                raise ValidationError("score must be a number between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")

            rating_id = self._next_id()
            rating = Rating(
                rating_id, rater_id, ratee_id, score, feedback, task_id, self._now()
            )
            self.performance.ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return rating.clone()

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance.ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / float(count) if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            durations = self._completion_durations(tasks)
            avg_time = (
                sum(durations) / float(len(durations)) if durations else None
            )

            ratings = self.performance.ratings_by_ratee.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / float(rating_count)
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completed / float(total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # --------------------------------------------------------------- reports
    def _task_summary(self, task):
        return {
            "id": task.id,
            "project_id": task.project_id,
            "title": task.title,
            "status": task.status.value,
            "assignee_id": task.assignee_id,
            "deadline": task.deadline.isoformat() if task.deadline else None,
            "started_at": task.started_at.isoformat() if task.started_at else None,
            "completed_at": (
                task.completed_at.isoformat() if task.completed_at else None
            ),
        }

    def _user_metrics(self, user_id, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = self._completion_durations(tasks)
        avg_time = sum(durations) / float(len(durations)) if durations else None
        ratings = self.performance.ratings_by_ratee.get(user_id, [])
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / float(rating_count)
            if rating_count
            else 0.0
        )
        username = ""
        user = self.users.items.get(user_id)
        if user is not None:
            username = user.username
        return {
            "user_id": user_id,
            "username": username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / float(total) if total else 0.0,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def project_progress_report(self, project_id):
        with self._lock:
            project = self._require_project(project_id)
            ids = self.tasks.by_project.get(project_id, [])
            tasks = [self.tasks.items[tid] for tid in ids if tid in self.tasks.items]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            completed = 0
            overdue = 0
            now = self._now()
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / float(total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                ids = self.tasks.by_project.get(project_id, [])
                scope_tasks = [
                    self.tasks.items[tid] for tid in ids if tid in self.tasks.items
                ]
            else:
                scope_tasks = list(self.tasks.items.values())

            grouped = {}
            for task in scope_tasks:
                if task.assignee_id is not None:
                    grouped.setdefault(task.assignee_id, []).append(task)

            rows = [
                self._user_metrics(uid, grouped[uid])
                for uid in sorted(grouped)
            ]

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._tasks_for_assignee(user_id), key=lambda t: t.id)
            metrics = self._user_metrics(user_id, tasks)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": metrics["username"],
                "total_tasks": metrics["total_tasks"],
                "completed_tasks": metrics["completed_tasks"],
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": metrics["completion_rate"],
                "average_completion_time": metrics["average_completion_time"],
                "rating_count": metrics["rating_count"],
                "rating_average": metrics["rating_average"],
                "tasks": [self._task_summary(t) for t in tasks],
            }
            return report

    # ---------------------------------------------------------------- export
    def export_report(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)

        rows = report.get("rows")
        tasks = report.get("tasks")
        if isinstance(rows, list):
            records = rows
        elif isinstance(tasks, list):
            records = tasks
        else:
            records = None

        if records is not None:
            columns = []
            for record in records:
                for key in record.keys():
                    if key not in columns:
                        columns.append(key)
            if not columns:
                columns = list(
                    k for k, v in report.items()
                    if not isinstance(v, (dict, list))
                ) or ["report_type"]
                writer.writerow(columns)
                writer.writerow([_csv_value(report.get(c)) for c in columns])
                return buffer.getvalue()
            writer.writerow(columns)
            for record in records:
                writer.writerow([_csv_value(record.get(c)) for c in columns])
            return buffer.getvalue()

        # Flat scalar report (e.g. project progress): emit a key/value table.
        scalar_items = [
            (k, v) for k, v in report.items() if not isinstance(v, (dict, list))
        ]
        if not scalar_items:
            scalar_items = [("report_type", report.get("report_type", "report"))]
        writer.writerow([k for k, _ in scalar_items])
        writer.writerow([_csv_value(v) for _, v in scalar_items])
        return buffer.getvalue()

    @classmethod
    def _export_pdf(cls, report):
        lines = cls._report_to_lines(report)

        content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
        for index, line in enumerate(lines):
            if index > 0:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(_pdf_escape(line)))
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray()
        pdf += b"%PDF-1.4\n"
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(number).encode("ascii")
            pdf += body
            pdf += b"\nendobj\n"

        xref_pos = len(pdf)
        size = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(size).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
        pdf += b"startxref\n"
        pdf += str(xref_pos).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)

    @staticmethod
    def _report_to_lines(report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for inner_key, inner_value in value.items():
                    lines.append("  {0} = {1}".format(inner_key, inner_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
                for item in value:
                    lines.append("  {0}".format(item))
            else:
                lines.append("{0} = {1}".format(key, value))
        return lines
